import React, { useState, useRef, useEffect } from 'react';
import { Container, TextField, IconButton, Paper, Typography, Box, Drawer, List, ListItem, ListItemIcon, ListItemText, Divider } from '@mui/material';
import { Send, AttachFile, ChatBubbleOutline, FolderShared, UploadFile } from '@mui/icons-material';
import ReactMarkdown from 'react-markdown';

function App() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [knowledgeFiles, setKnowledgeFiles] = useState([]);
  const fileInputRef = useRef(null);
  const kbInputRef = useRef(null);
  const chatEndRef = useRef(null);

  // 页面加载时拉取云端历史记录和知识库
  useEffect(() => {
    fetchHistory();
    fetchKnowledgeFiles();
  }, []);

  // 自动滚动到最新消息
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const fetchHistory = async () => {
    try {
      const res = await fetch('http://localhost:8080/api/history');
      const data = await res.json();
      setMessages(data);
    } catch (e) { console.error("无法加载历史记录", e); }
  };

  const fetchKnowledgeFiles = async () => {
    try {
      const res = await fetch('http://localhost:8080/api/knowledge/files');
      const data = await res.json();
      setKnowledgeFiles(data);
    } catch (e) { console.error("无法加载知识库", e); }
  };

  const handleKBUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const formData = new FormData();
    formData.append('file', file);
    try {
      await fetch('http://localhost:8080/api/knowledge/upload', { method: 'POST', body: formData });
      fetchKnowledgeFiles(); // 重新加载列表
    } catch (e) { console.error("知识库上传失败"); }
  };

  // 📝 简化后的纯文本发送逻辑 (非流式，一口气接收)
  const handleSendText = async () => {
    if (!input.trim()) return;

    const newMsgs = [...messages, { role: 'user', content: input }];
    setMessages(newMsgs);
    setInput('');
    setLoading(true);

    try {
      const response = await fetch('http://localhost:8080/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ messages: newMsgs })
      });

      // 直接获取完整的字符串返回
      const text = await response.text();

      // 一次性更新到界面上，保证排版完美
      setMessages(prev => [...prev, { role: 'assistant', content: text }]);
    } catch (e) {
      console.error('Error:', e);
      setMessages(prev => [...prev, { role: 'assistant', content: "[网络连接异常或后端服务未启动]" }]);
    } finally {
      setLoading(false);
    }
  };

  // 🎬 简化后的多模态文件上传逻辑 (非流式，一口气接收)
  const handleFileUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    let type = file.type.includes('image') ? 'image' : (file.type.includes('audio') ? 'audio' : 'video');

    // 把用户想问的话和文件名拼在一起展示
    const userMessageContent = `[上传了文件: ${file.name}]\n${input || "请分析这个文件"}`;
    setMessages([...messages, { role: 'user', content: userMessageContent }]);
    setLoading(true);

    const formData = new FormData();
    formData.append('file', file);
    formData.append('type', type);
    formData.append('prompt', input || "请分析这个文件");
    setInput('');

    try {
      const response = await fetch('http://localhost:8080/api/chat/media', {
        method: 'POST',
        body: formData
      });

      // 直接获取完整的字符串返回
      const text = await response.text();

      setMessages(prev => [...prev, { role: 'assistant', content: text }]);
    } catch (e) {
      console.error('文件处理流异常:', e);
      setMessages(prev => [...prev, { role: 'assistant', content: "[文件处理失败，请检查后端服务是否正常]" }]);
    } finally {
      setLoading(false);
      // 清空 input file 的值，允许重复上传同一个文件
      if (fileInputRef.current) {
        fileInputRef.current.value = null;
      }
    }
  };

  return (
      <Box sx={{ display: 'flex', height: '100vh', bgcolor: '#f4f6f8' }}>

        {/* 【左侧栏】：历史会话导览 */}
        <Drawer variant="permanent" sx={{ width: 260, flexShrink: 0, '& .MuiDrawer-paper': { width: 260, boxSizing: 'border-box', bgcolor: '#1c2536', color: '#fff' } }}>
          <Box sx={{ p: 2 }}>
            <Typography variant="h6" fontWeight="bold">AI 商业智能台</Typography>
          </Box>
          <Divider sx={{ bgcolor: 'rgba(255,255,255,0.1)' }} />
          <List>
            <ListItem button>
              <ListItemIcon><ChatBubbleOutline sx={{ color: '#fff' }}/></ListItemIcon>
              <ListItemText primary="默认会话空间" />
            </ListItem>
          </List>
        </Drawer>

        {/* 【中间】：核心交互工作区 */}
        <Box sx={{ flexGrow: 1, display: 'flex', flexDirection: 'column', p: 3 }}>
          <Paper elevation={0} sx={{ flex: 1, overflowY: 'auto', p: 3, mb: 2, borderRadius: 3, bgcolor: '#fff', border: '1px solid #e0e0e0' }}>
            {messages.map((m, i) => (
                <Box key={i} sx={{ display: 'flex', justifyContent: m.role === 'user' ? 'flex-end' : 'flex-start', mb: 3 }}>
                  <Box sx={{
                    p: 2, borderRadius: 2,
                    bgcolor: m.role === 'user' ? '#1976d2' : '#f8f9fa',
                    color: m.role === 'user' ? '#fff' : '#111827',
                    maxWidth: '80%',
                    border: m.role === 'assistant' ? '1px solid #e5e7eb' : 'none',
                    // 保留这些 CSS，可以让 ReactMarkdown 渲染出来的列表和段落更漂亮
                    whiteSpace: 'pre-wrap',
                    wordBreak: 'break-word',
                    '& p': { margin: 0, marginBottom: 1.5 },
                    '& ul, & ol': { marginTop: 0.5, marginBottom: 0.5, paddingLeft: 3 }
                  }}>
                    {/* 使用 ReactMarkdown 渲染最终文本 */}
                    <ReactMarkdown>{m.content}</ReactMarkdown>
                  </Box>
                </Box>
            ))}
            {loading && (
                <Box sx={{ display: 'flex', justifyContent: 'flex-start', mb: 3 }}>
                  <Box sx={{ p: 2, borderRadius: 2, bgcolor: '#f8f9fa', color: '#888', border: '1px solid #e5e7eb' }}>
                    <Typography variant="body2">AI 正在思考处理中，请稍候...</Typography>
                  </Box>
                </Box>
            )}
            <div ref={chatEndRef} />
          </Paper>

          <Box sx={{ display: 'flex', gap: 1, alignItems: 'center', bgcolor: '#fff', p: 1, borderRadius: 3, border: '1px solid #e0e0e0' }}>
            <input type="file" hidden ref={fileInputRef} onChange={handleFileUpload} />
            <IconButton onClick={() => fileInputRef.current.click()}><AttachFile /></IconButton>
            <TextField variant="standard" fullWidth value={input} onChange={e => setInput(e.target.value)} onKeyPress={e => e.key === 'Enter' && handleSendText()} placeholder="输入指令，或上传媒体文件..." InputProps={{ disableUnderline: true, sx: { px: 1 } }} />
            <IconButton onClick={handleSendText} disabled={loading} color="primary" sx={{ bgcolor: '#e3f2fd' }}><Send /></IconButton>
          </Box>
        </Box>

        {/* 【右侧栏】：私有知识库管理 */}
        <Drawer variant="permanent" anchor="right" sx={{ width: 280, flexShrink: 0, '& .MuiDrawer-paper': { width: 280, boxSizing: 'border-box', bgcolor: '#fff', borderLeft: '1px solid #e0e0e0' } }}>
          <Box sx={{ p: 2, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <Typography variant="subtitle1" fontWeight="bold">私有知识库 (RAG)</Typography>
            <input type="file" hidden ref={kbInputRef} onChange={handleKBUpload} />
            <IconButton size="small" onClick={() => kbInputRef.current.click()} color="primary"><UploadFile /></IconButton>
          </Box>
          <Divider />
          <List sx={{ px: 1 }}>
            {knowledgeFiles.length === 0 ? (
                <Typography variant="caption" color="textSecondary" sx={{ p: 2, display: 'block', textAlign: 'center' }}>暂无上传文档</Typography>
            ) : (
                knowledgeFiles.map((file, i) => (
                    <ListItem key={i} sx={{ bgcolor: '#f4f6f8', borderRadius: 1, mb: 1 }}>
                      <ListItemIcon sx={{ minWidth: 36 }}><FolderShared fontSize="small" color="action" /></ListItemIcon>
                      <ListItemText primary={file} primaryTypographyProps={{ noWrap: true, variant: 'body2' }} />
                    </ListItem>
                ))
            )}
          </List>
        </Drawer>
      </Box>
  );
}

export default App;
